import type { TextFieldProps } from ':components/TextField';
import type { Placement } from '@floating-ui/react';
export interface DateMatchGroups {
    groups: {
        [key: string]: string;
    };
}
export type RangeDateValue = string[];
export type SingleDateValue = string;
export type DateValue = SingleDateValue | RangeDateValue;
export type DatePickerProps = Omit<TextFieldProps, 'startAdornment' | 'endAdornment' | 'onChange'> & {
    /**
     * Значение даты
     */
    value?: SingleDateValue;
    /**
     * Минимальная дата, которую может выбрать пользователь
     * Сравнение выполняется по календарному дню на UTC-полуночь, чтобы избежать ошибок из-за часовых поясов
     */
    minDate?: SingleDateValue;
    /**
     * Максимальная дата, которую может выбрать пользователь
     * Сравнение выполняется по календарному дню на UTC-полуночь, чтобы избежать ошибок из-за часовых поясов
     */
    maxDate?: SingleDateValue;
    /**
     * Отключает возможность выбрать начальную дату
     */
    disabledStartDate?: boolean;
    /**
     * Отключает возможность выбрать конечную дату
     */
    disabledEndDate?: boolean;
    /**
     * Пользовательское имя класса
     */
    className?: string;
    /**
     * Идентификатор для автоматизированного тестирования
     */
    dataTestId?: string;
    /**
     * Обработчик вызываемый при изменении значения `value`
     */
    onChange?: (date: SingleDateValue) => void;
    /**
     * Обработчик вызываемый при закрытии "всплывашки" календаря
     */
    onClose?: () => void;
    /**
     * Обработчик вызываемый при открытии "всплывашки" календаря
     */
    onOpen?: () => void;
    /**
     * Включается мобильное представление календаря
     */
    mobileView?: boolean;
    /**
     * Ref на DOM элемент календаря
     */
    datepickerRef?: React.RefObject<HTMLDivElement>;
    /**
     * Обработчик события нажатия кнопки "Сохранить"
     *
     * если передан кнопка будет отрисована
     */
    onSaveClick?: () => void;
    /**
     * Коллбек, который определяет должен ли день быть задисейблен
     */
    excludeDate?: (date: Date) => boolean;
    /**
     * Дата которая определяет, какая страница календаря должна показываться
     * @example Thu Feb 29 2024 10:27:58 GMT+0000
     * @deprecated Используйте `initialViewDate` вместо этого.
     */
    customViewDate?: string;
    /**
     * Дата которая определяет, какая страница календаря должна показываться
     * Принимает тот же формат что и value (ISO строка)
     * @example "2024-02-15T10:27:58.000Z" или "2024-02-15"
     */
    initialViewDate?: string;
    /**
     * Коллбек, который определяет должен ли день быть выходным (цифры красного цвета)
     */
    holidaysDate?: (date: Date) => boolean;
    enableTimePicker?: boolean;
    timeRange?: [string, string];
    outOfRangeErrorText?: string;
    /**
     * Добавляет пользовательский класс для дропдауна календаря
     */
    dropdownClassName?: string;
    /**
     * Определяет, включена дефолтная или Imask маска
     * @default false
     */
    enableImaskConfig?: boolean;
    /**
     * Конфиг для маскирования ввода
     * Используется, если enableImaskConfig = true
     */
    maskConfig?: any;
    /**
     * Определяет, должно ли наложение блокировать прокрутку на теле документа.
     * @default true
     */
    overlayScroll?: boolean;
    /**
     * Указывает, нужно ли рендерить оверлей
     * */
    shouldRenderOverlay?: boolean;
    /**
     * Добавляет className для Overlay
     * */
    overlayClassName?: string;
    /**
     * Выравнивание дропдавна
     * */
    alignDropDown?: Placement;
    /**
     * Часовой пояс (IANA string). Если не задан, используем локальный пояс.
     * Например: 'Europe/Moscow', 'America/New_York', 'Asia/Tokyo',
     */
    timeZone?: string;
    /**
     * Коллбек для кастомизации дня в календаре
     * Может возвращать строку с классами или React элемент для рендера внутри ячейки дня
     */
    customizeDay?: (date: Date) => {
        className?: string;
        content?: React.ReactNode;
    };
    /**
     * Скрывает выпадающее меню, даже если состояние open равно true
     * @default false
     */
    hideDropDown?: boolean;
    /**
     * Настройки отображения дней соседних месяцев
     */
    showAdjacentMonthDays?: {
        /**
         * Показывать дни предыдущего месяца
         */
        showPrevious?: boolean;
        /**
         * Показывать дни следующего месяца
         */
        showNext?: boolean;
    };
    /**
     * Разрешает выбор дат соседних месяцев (предыдущего и следующего)
     * Работает только при включенном showAdjacentMonthDays
     */
    allowAdjacentMonthSelection?: boolean;
    clearOnExcludedDateClose?: boolean;
};
